head.script:
/**
 * 화 면 명 : 거래처채권채무조회
 * 메뉴경로 : 회계/재무회계/일반회계/특수거래처/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ac/fi/gnrlaccount/specialpart/fi_206_01_03b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-10-01
 * 수정이력  :
 *    - 2025-10-01      정승혜    최초작성
 *    - 2025-11-25      정승혜    준수사항 적용, udc
 *    - 2025-12-29      정승혜    자회사로직수정 / 기타수정
 *    - 2026-01-19      정승혜    submitdone 조건수정
 */

scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin"); // ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님  
scwin.vUserHomeClsCd = scwin.memJson.userHomeClsCd;
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.memJson.coCd) ? '' : scwin.memJson.coCd;
scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.memJson.coClsCd) ? '' : scwin.memJson.coClsCd;

//hidden
scwin.txtCoClsCd = "";

scwin.isSubCompany = false;

scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.isStarted = true; // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 실행-팝업 리턴 시간차)

  //-------------------------------------------------------------------------
  // 화면로딩시
  //-------------------------------------------------------------------------
scwin.onpageload = function() {
    // getCodeList
    const codeOptions = [
        { grpCd : "FI060", compID : "lc_concernedCd" },
        { grpCd : "FI059", compID : "lc_speclCntHourCls, gr_concernedCd:speclCntHourCls" },
    ];
    $c.data.setCommonCode(codeOptions);    

};

// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        scwin.f_Header();
        scwin.f_setCompanyInfo();
    }, {"delay":100});    

};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() { 
    let dltStr = "dlt_commonCodeFI060"; 
    let dlt = $c.gus.object(dltStr);

    $c.gus.copy(dltStr, "dlt_commonCodeFI060_1", true);
    $c.gus.copy(dltStr, "dlt_commonCodeFI060_2", true);
    $c.gus.copy(dltStr, "dlt_commonCodeFI060_3", true);

    let dlt1 = $c.gus.object("dlt_commonCodeFI060_1"); // 객체화
    let dlt2 = $c.gus.object("dlt_commonCodeFI060_2"); // 객체화
    let dlt3 = $c.gus.object("dlt_commonCodeFI060_3"); // 객체화

    $c.data.dataListFilter(dlt1, "fltrCd1 == '1'");
    $c.data.dataListFilter(dlt2, "fltrCd1 == '2'");
    $c.data.dataListFilter(dlt3, "fltrCd1 == '3'");

    dlt_commonCodeFI060.sort("cd", 0);
    dlt_commonCodeFI060_1.sort("cd", 0);
    dlt_commonCodeFI060_2.sort("cd", 0);
    dlt_commonCodeFI060_3.sort("cd", 0);
};

  	//-------------------------------------------------------------------------
	// 자회사 회계 시스템 추가에 따른 설정 
	//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if(scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD){
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');

};

	//-------------------------------------------------------------------------
	// 회사 입력 팝업 
	//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    let rtnList = await udc_companyInfo.cfCommonPopUp(scwin.udc_companyInfo_callBackFunc
                                ,ed_coCd.getValue(), ed_coNm.getValue(),pWinCloseTF,null,null,null,null,null,null,null,null,null

    );
};

scwin.udc_companyInfo_callBackFunc = function(rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ed_coCd.setValue(rtnList[0]);
        ed_coNm.setValue(rtnList[5]);
        ed_coCd.options.hidVal = rtnList[0]; // 히든값
        scwin.txtCoClsCd = rtnList[1];
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        ed_coCd.options.hidVal = "";
        scwin.txtCoClsCd = "";
    }

    if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU){  // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    }

    if ( scwin.isStarted == true )  // 최초 이벤트 여부 (자회사 여부를 최초 한번만 실행-팝업 리턴 시간차)
    {
        // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
        if ("T" == scwin.privAdmin || !scwin.isSubCompany) {  
            $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company]);
        }else{
            $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);
        }
        scwin.isStarted = false;
    }
}

  //-------------------------------------------------------------------------
  // 재조회
  //-------------------------------------------------------------------------
scwin.f_SearchClear = function (e) {
    $c.gus.cfInitObjects(searchTable);
};

  //-------------------------------------------------------------------------
  // 조회조건 셋팅 
  //-------------------------------------------------------------------------
scwin.f_Setting = function() {
    ed_postDtSt.setValue(scwin.vCurDate.substring(0, 4) + "01");
    ed_postDtEnd.setValue(scwin.vCurDate.substring(0, 6));
    lc_speclCntHourCls.setSelectedIndex(-1);
    lc_concernedCd.setSelectedIndex(0);
    lc_printStd.setSelectedIndex(-1);
};

  //-------------------------------------------------------------------------
  // 헤더생성
  //-------------------------------------------------------------------------
scwin.f_Header = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
    scwin.f_Setting();
};

  //-------------------------------------------------------------------------
  // 조회
  //-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    let ret = await $c.gus.cfValidate([ed_coCd]);
    if (!ret){
        return;
    }
    $c.sbm.execute(sbm_retrieve);
};

  //-------------------------------------------------------------------------
  // 구분 변경 
  //-------------------------------------------------------------------------
scwin.f_Gbn = function() {
    if (lc_speclCntHourCls.getValue() == "1"){
        lc_concernedCd.setNodeSet("data:dlt_commonCodeFI060_1", "cdNm", "cd");
        lc_concernedCd.setValue("");
    } else if (lc_speclCntHourCls.getValue() == "2"){
        lc_concernedCd.setNodeSet("data:dlt_commonCodeFI060_2", "cdNm", "cd");
        lc_concernedCd.setValue("");
    } else if (lc_speclCntHourCls.getValue() == "3"){
        lc_concernedCd.setNodeSet("data:dlt_commonCodeFI060_3", "cdNm", "cd");
        lc_concernedCd.setValue(""); 
    }else{
        lc_concernedCd.setNodeSet("data:dlt_commonCodeFI060", "cdNm", "cd");
        lc_concernedCd.setValue("");
    }
};

//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
    // 엑셀다운 8+16
scwin.f_Excel  = async function (e) {
    let confirm = await $c.win.confirm("Excel로 다운로드 하시겠습니까?")
    if( confirm ) {
        const options = {
            fileName : "거래처채권채무조회.xlsx", 
            sheetName : "거래처채권채무조회",
            type : 1
        };
        $c.data.downloadGridViewExcel(gr_concernedCd, options);
    }  
};

    //-------------------------------------------------------------------------
    // function name : f_grdHeiht
    // function desc : 그리드 높이 늘리기
    // function Parameter : null
    //-------------------------------------------------------------------------
scwin.f_grdHeiht = function (e) {

};

// 팝업 클릭 이벤트 함수
scwin.udc_companyInfo_onclickEvent = async function (e) {
    scwin.f_PopUpCompanyInfo('F');
};

// 팝업 포커스 관련 함수
scwin.udc_companyInfo_onblurCodeEvent = function (e) {
    ed_coNm.setValue("");
    if (ed_coCd.getValue() !== "") {
        scwin.f_PopUpCompanyInfo('T');
    }
};

// 구분 변경시
scwin.lc_speclCntHourCls_onchange = function (info) {
    scwin.f_Gbn();
};

// 서브미션
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    totalRows.setValue(ds_concernedCd.getRowCount());
    if (ds_concernedCd.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002); 
    } else {
        $c.gus.cfGoPrevPosition(gr_concernedCd,0); 
    }
};
